//! Embedded compatibility dataset for the `compat/compat` rule.
//!
//! The dataset (`compat_data.json`) is generated by `tasks/linter_compat_data`
//! from `ast-metadata-inferer` (MDN browser-compat-data derived) and
//! `caniuse-lite`. See that task's README for details.

use std::sync::LazyLock;

use rustc_hash::{FxHashMap, FxHashSet};
use serde::Deserialize;

/// A single MDN-derived API record.
pub struct MdnApi {
    /// e.g. `"navigator.serviceWorker"`, `"AbortController"`.
    pub proto_chain_id: &'static str,
    /// AST node types this API is linted on, encoded as characters:
    /// `M` = MemberExpression, `C` = CallExpression, `N` = NewExpression.
    pub ast_node_types: &'static str,
    /// Whether this is an ECMAScript API (`kind == "es"`), as opposed to a
    /// web platform API.
    pub is_es: bool,
    /// Map of browserslist target name (e.g. `"chrome"`, `"ios_saf"`) to the
    /// version the API was added in. An empty string means the API is not
    /// supported by that browser at all.
    pub support: FxHashMap<&'static str, &'static str>,
}

/// caniuse-lite support entry for one browser: the list of
/// `(version, supported)` pairs in caniuse-lite order, where `supported` is
/// whether the caniuse flags include `y`.
pub type CaniuseBrowserStats = Vec<(&'static str, bool)>;

pub struct CompatData {
    pub mdn: Vec<MdnApi>,
    /// caniuse feature id -> browser name -> stats.
    pub caniuse: FxHashMap<&'static str, FxHashMap<&'static str, CaniuseBrowserStats>>,
    /// Browser global names from the `globals` npm package.
    pub browser_globals: FxHashSet<&'static str>,
}

#[derive(Deserialize)]
struct RawMdnApi<'a>(&'a str, &'a str, u8, #[serde(borrow)] FxHashMap<&'a str, &'a str>);

type RawCaniuseData<'a> = FxHashMap<&'a str, FxHashMap<&'a str, Vec<(&'a str, u8)>>>;

#[derive(Deserialize)]
struct RawCompatData<'a> {
    #[serde(borrow)]
    mdn: Vec<RawMdnApi<'a>>,
    #[serde(borrow)]
    caniuse: RawCaniuseData<'a>,
    #[serde(borrow, rename = "browserGlobals")]
    browser_globals: Vec<&'a str>,
}

static COMPAT_DATA_JSON: &str = include_str!("compat_data.json");

pub static COMPAT_DATA: LazyLock<CompatData> = LazyLock::new(|| {
    let raw: RawCompatData<'static> = serde_json::from_str(COMPAT_DATA_JSON)
        .expect("compat_data.json should be a valid compat dataset");
    CompatData {
        mdn: raw
            .mdn
            .into_iter()
            .map(|RawMdnApi(proto_chain_id, ast_node_types, is_es, support)| MdnApi {
                proto_chain_id,
                ast_node_types,
                is_es: is_es == 1,
                support,
            })
            .collect(),
        caniuse: raw
            .caniuse
            .into_iter()
            .map(|(feature, browsers)| {
                (
                    feature,
                    browsers
                        .into_iter()
                        .map(|(browser, versions)| {
                            (browser, versions.into_iter().map(|(v, y)| (v, y == 1)).collect())
                        })
                        .collect(),
                )
            })
            .collect(),
        browser_globals: raw.browser_globals.into_iter().collect(),
    }
});

/// Maps a browserslist target id to the full name shown to users.
/// Mirrors `STANDARD_TARGET_NAME_MAPPING` in eslint-plugin-compat's
/// `src/constants.ts`; unknown ids fall back to the raw id.
pub fn target_display_name(target: &str) -> &str {
    match target {
        "chrome" => "Chrome",
        "firefox" => "Firefox",
        "safari" => "Safari",
        "ios_saf" => "iOS Safari",
        "ie" => "IE",
        "ie_mob" => "IE Mobile",
        "edge" => "Edge",
        "baidu" => "Baidu",
        "electron" => "Electron",
        "blackberry_browser" => "Blackberry Browser",
        "edge_mobile" => "Edge Mobile",
        "and_uc" => "Android UC Browser",
        "and_chrome" => "Android Chrome",
        "and_firefox" => "Android Firefox",
        "and_webview" => "Android Webview",
        "and_samsung" => "Samsung Browser",
        "and_opera" => "Opera Android",
        "opera" => "Opera",
        "opera_mini" => "Opera Mini",
        "opera_mobile" => "Opera Mobile",
        "node" => "Node.js",
        "kaios" => "KaiOS",
        other => other,
    }
}
